// OAuth 2.0 Client for managing Access and Refresh Tokens

class OAuthClient {
  constructor(clientId, authUrl, tokenUrl, redirectUri) {
    this.clientId = clientId;
    this.authUrl = authUrl;
    this.tokenUrl = tokenUrl;
    this.redirectUri = redirectUri;
    this.accessTokenKey = 'access_token';
    this.refreshTokenKey = 'refresh_token';

    this.init();
  }

  init() {
    const params = new URLSearchParams(window.location.search);
    if (params.has('code')) {
      this.fetchTokens(params.get('code'));
    } else {
      const accessToken = localStorage.getItem(this.accessTokenKey);
      if (accessToken && !this.isTokenExpired()) {
        console.log('Access token is valid');
      } else {
        const refreshToken = localStorage.getItem(this.refreshTokenKey);
        if (refreshToken) {
          this.refreshAccessToken(refreshToken);
        } else {
          this.redirectToAuth();
        }
      }
    }
  }

  redirectToAuth() {
    const authUrlWithParams = `${this.authUrl}?client_id=${this.clientId}&redirect_uri=${encodeURIComponent(this.redirectUri)}&response_type=code&scope=your_scope`;
    window.location.href = authUrlWithParams;
  }

  fetchTokens(code) {
    fetch(this.tokenUrl, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: `grant_type=authorization_code&code=${code}&redirect_uri=${encodeURIComponent(this.redirectUri)}&client_id=${this.clientId}`,
    })
      .then(response => response.json())
      .then(data => {
        this.storeTokens(data.access_token, data.refresh_token, data.expires_in);
      });
  }

  storeTokens(accessToken, refreshToken, expiresIn) {
    const expiryTime = Date.now() + expiresIn * 1000;
    localStorage.setItem(this.accessTokenKey, JSON.stringify({ token: accessToken, expiry: expiryTime }));
    localStorage.setItem(this.refreshTokenKey, refreshToken);
  }

  isTokenExpired() {
    const token = JSON.parse(localStorage.getItem(this.accessTokenKey));
    return Date.now() > token.expiry;
  }

  refreshAccessToken(refreshToken) {
    fetch(this.tokenUrl, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: `grant_type=refresh_token&refresh_token=${refreshToken}&client_id=${this.clientId}`,
    })
      .then(response => response.json())
      .then(data => {
        this.storeTokens(data.access_token, data.refresh_token, data.expires_in);
      });
  }
}

